import React from "react";
import { useHistory } from "react-router";
import { CurrentSeasonStore } from "../store/CurrentSeasonStore";
import EpisodesHolder from "./EpisodesHolder";

function SeasonEpisodesPage() {
  const history = useHistory();

  const { season_number, season_name, id, season_poster_path, tv_name } =
    CurrentSeasonStore.useState((s) => s);

  return (
    <div className="SeasonEpisodesPage">
      <div className="SeasonBanner">
        <h1>
          {tv_name} {season_name}
        </h1>
      </div>
      <div>
        <EpisodesHolder />
      </div>

      <div
        className="shape"
        id="robotShape"
        onMouseEnter={() => navigator.vibrate(200)}
      >
        <span>
          <span></span>
          <span></span>
        </span>
      </div>
    </div>
  );
}

export default SeasonEpisodesPage;
