import React, { useState, useEffect } from "react";
import { useHistory, useParams } from "react-router";
import requests from "../requests";
import YouTube from "react-youtube";
import movieTrailer from "movie-trailer";
import axios from "axios";
import SeasonsHolder from "./SeasonsHolder";
import { Helmet } from "react-helmet";
import useStatePromise from "use-state-promise";
import Collection from "./Collection";
import Loading from "./Loading";
import { BiMessageSquareAdd } from "react-icons/bi";
import { BsPeople } from "react-icons/bs";
import { FaPlay, FaStar } from "react-icons/fa";
import Row from "./Row";

function AllAbout({ watchList, watchListLen, setWatchList, setWatchListLen }) {
  const { type, id } = useParams();

  const API_KEY = "20108f1c4ed38f7457c479849a9999cc";

  const history = useHistory();

  const [trailerUrl, setTrailerUrl] = useState("");

  const [showTrailer, setShowTrailer] = useState(false);
  const [inWatchList, setInWatchList] = useState(false);
  const [showWatch, setShowWatch] = useState(false);
  const [isTvShow, setIsTvShow] = useState(false);

  const [movie, setMoviePromes, setMovie] = useStatePromise({});

  const [isPartOfCollection, setIsPartOfCollection] = useState(false);

  const [isLoading, setisLoading] = useState(false);

  const [genres, setgenres] = useState([]);

  const [release_date, setrelease_date] = useState("");

  // after getting the type and the id from the params now go fetch for the current and set the movie value for it
  useEffect(() => {
    setInWatchList(false);
    document.documentElement.scrollTop = 0;
    async function fetchIt() {
      setisLoading(true);
      if (type === "tv") {
        setIsTvShow(true);
      } else {
        setIsTvShow(false);
      }

      const res = await axios.get(
        `https://api.themoviedb.org/3/${type}/${id}?api_key=${API_KEY}`
      );

      setMoviePromes(() => {
        setMovie({ ...res.data });
        return movie;
      }).then((movie) => {
        setgenres([...movie.genres]);
        setrelease_date(movie.release_date);
        if (movie?.belongs_to_collection) {
          setIsPartOfCollection(true);
        } else {
          setIsPartOfCollection(false);
        }
        setisLoading(false);
      });
    }
    fetchIt();
  }, [id, type]);

  // extract movie infos
  const backdrop_path = requests?.image_api + movie?.backdrop_path;
  const poster_path = requests?.image_api + movie?.poster_path;
  const { title, vote_average, original_name, overview } = movie;

  // Youtube opts
  const opts = {
    width: "100%",
    height: "400px",
  };

  // get the movie trailer url on first load
  useEffect(() => {
    movieTrailer(title || movie.name || original_name || "")
      .then((url) => {
        const urlParams = new URLSearchParams(new URL(url).search);
        setTrailerUrl(urlParams.get("v"));
      })
      .catch((err) => false);

    if (watchList !== "") {
      if (
        watchList.some((e) => e.movieId === movie.id && e.mediaType === type)
      ) {
        setInWatchList(true);
      }
    }
  }, [id, movie, type]);

  const addToWatchListHandler = (e) => {
    setWatchList([
      ...watchList,
      { movieId: movie.id, mediaType: type ? type : movie.media_type },
    ]);
    localStorage.setItem("watchlist", JSON.stringify(watchList));
    setWatchListLen(watchListLen++);
    e.target.style.display = "none";
  };

  return (
    <>
      {isLoading && <Loading />}
      <div
        className="all_about"
        style={{
          backgroundImage: `url(${backdrop_path})`,
          minHeight: window.innerHeight - 75.2,
        }}
      >
        <Helmet>
          <title>{title || original_name}</title>
          <meta name="description" content={overview}></meta>

          <meta property="og:type" content="website"></meta>
          <meta property="og:url" content="https://moviea.netlify.app/"></meta>

          <meta property="og:image" content={backdrop_path}></meta>
        </Helmet>
        *<div className="cover"></div>
        <div className="inner_all_about">
          <div className="poster_holder">
            <img src={poster_path} alt={id} />
          </div>
          <div className="all_about_text_holder">
            <h1>
              {title || original_name}{" "}
              <span style={{ fontSize: ".7em", opacity: ".7" }}>
                {release_date ? `( ${release_date.substring(0, 4)} )` : ""}
              </span>
            </h1>
            <div className="genresHlder">
              {genres.map((genre, key) => (
                <span
                  key={key}
                  className="genre"
                  onClick={() =>
                    history.push(`/discover/genre/${genre.id}/${genre.name}`)
                  }
                >
                  {genre.name}{" "}
                </span>
              ))}
            </div>
            <h3>
              vote average {vote_average} <FaStar />
            </h3>
            <h3>
              {isTvShow
                ? `number of seasons : ${movie.number_of_seasons} / episodes number : ${movie.number_of_episodes} `
                : ""}
            </h3>
            <p>{overview}</p>
            <div className="all_about_buttons_row">
              {!isTvShow && (
                <button id="Trailer" onClick={() => setShowTrailer(true)}>
                  trailer
                </button>
              )}

              {inWatchList ? (
                ""
              ) : (
                <button id="watchList" onClick={addToWatchListHandler}>
                  <BiMessageSquareAdd /> list
                </button>
              )}

              {!isTvShow && (
                <button id="Trailer" onClick={() => setShowWatch(true)}>
                  <FaPlay style={{ fontSize: "1.2em" }} /> Watch
                </button>
              )}

              <button
                onClick={() =>
                  history.push(`/casts/${type}/${id}/${title || original_name}`)
                }
              >
                <BsPeople /> casts
              </button>
            </div>
          </div>
        </div>
        {showTrailer && (
          <div className="trailer_popup" onClick={() => setShowTrailer(false)}>
            <div className="youtube_vedio_holder">
              <YouTube videoId={trailerUrl} opts={opts} />
            </div>
          </div>
        )}
        {showWatch && (
          <div className="trailer_popup" onClick={() => setShowWatch(false)}>
            {/* https://imdbapi.ml/embed/ */}
            <iframe
              title="film"
              src={`https://www.2embed.ru/embed/tmdb/movie?id=${id}`}
              width="100%"
              height="100%"
              frameborder="0"
              allowFullScreen
            />
          </div>
        )}
      </div>

      {isTvShow && <SeasonsHolder id={id} />}
      {isPartOfCollection && <Collection movie={movie} />}

      <Row
        fetchUrl={`/${type}/${id}/similar?api_key=${requests.apiKey}`}
        isFirst={false}
        isLarge={false}
        mediaType={type}
        setIsLoading={setisLoading}
        title="Similar"
        key="545455"
      />
    </>
  );
}

export default AllAbout;
