import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import requests from "../requests";
import { FaStar } from "react-icons/fa";
import axios from "axios";

function CastCard({ name, profile_path, id, popularity, credit_id }) {
  const [castsAs, setcastsAs] = useState("");
  useEffect(() => {
    const fetchData = async () => {
      const res = await axios.get(
        `https://api.themoviedb.org/3/credit/${credit_id}?api_key=${requests.apiKey}`
      );

      setcastsAs(res.data.media.character);
    };
    fetchData();
  }, [id, credit_id]);
  if (!profile_path) return false;
  return (
    <div className="MovieCard CastCard">
      <Link to={`/about-cast/${id}/${credit_id}`}>
        <img src={requests.image_api + profile_path} alt={name} key={id} />
      </Link>
      <h4 className="voteAvarage subTitleAboutCast">
        <span>{name.slice(0, 13)}</span>
        <span style={{ display: "flex", alignItems: "center" }}>
          {Math.round(popularity)} <FaStar style={{ marginLeft: ".2em" }} />
        </span>
      </h4>
      <span className="vorteAvarage castAs">{castsAs}</span>
    </div>
  );
}

export default CastCard;
